class Solution:
    def solve(self, graph):
        n = len(graph)
        low = [0] * n
        disc = [0] * n
        vis = [False] * n
        time = 0

        def dfs(u):
            nonlocal time
            vis[u] = True
            disc[u] = low[u] = time
            time += 1
            for v in graph[u]:
                if not vis[v]:
                    dfs(v)
                    low[u] = min(low[u], low[v])
                else:
                    low[u] = min(low[u], disc[v])

            if low[u] == disc[u]:
                return True

            return False

        for x in range(n):
            if not vis[x] and dfs(x):
                return True

        return False

    def main(self):
        import sys
        input = sys.stdin.readline
        n = int(input())
        graph = [[] for _ in range(n)]

        for i in range(n - 1):
            u, v = [int(x) for x in input().split()]
            graph[u].append(v)
            graph[v].append(u)

        if self.solve(graph):
            print('1')
        else:
            print('0')

