class Solution {
public:
    bool solve(vector<vector<int>>& graph) {
        int n = graph.size();
        int low[n];
        int disc[n];
        bool vis[n];

        for (int i = 0; i < n; i++) {
            disc[i] = low[i] = 0;
            vis[i] = false;
        }

        int time = 0;

        void dfs(int u) {
            vis[u] = true;
            disc[u] = low[u] = time;
            time += 1;

            for (int v = 0; v < graph[u].size(); v++) {
                int vv = graph[u][v];

                if (!vis[vv]) {
                    dfs(vv);
                    low[u] = min(low[u], low[vv]);
                } else {
                    low[u] = min(low[u], disc[vv]);
                }
            }

            if (low[u] == disc[u]) {
                return true;
            }

            return false;
        }

        for (int x = 0; x < n; x++) {
            if (!vis[x] && dfs(x)) {
                return true;
            }
        }

        return false;

    }
};

int main() {
    Solution solution;

    int n;
    cin >> n;
    vector<vector<int>> graph;

    for (int i = 0; i < n; i++) {
        graph.push_back(vector<int>());
    }

    for (int i = 0; i < n - 1; i++) {
        int u, v;
        cin >> u >> v;
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    if (solution.solve(graph)) {
        cout << "1";
    } else {
        cout << "0";
    }

    return 0;
}
